   132	     * The default implementation uses {@code SHA-256} so the same name is always
   133	     * returned for the same statement.
   134	     * <p>
   135	     * As there is always a small risk of duplicity, named statements are recommended!
   136	     *
   137	     * @param type      type of the statement
   138	     * @param statement statement that is going to be executed
   139	     * @return name of the statement
   140	     */
   141	    protected String generateName(DbStatementType type, String statement) {
   142	        String sha256;
   143	        try {
   144	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
   145	            digest.update(statement.getBytes(StandardCharsets.UTF_8));
   146	            sha256 = Base64.getEncoder().encodeToString(digest.digest());
   147	        } catch (NoSuchAlgorithmException ignored) {
