    38	/**
    39	 * JDBC implementation of {@link DbStatementDml}.
    40	 */
    41	class JdbcStatementDml extends JdbcStatement<DbStatementDml> implements DbStatementDml {
    42	
    43	    static final String[] EMPTY_STRING_ARRAY = new String[0];
    44	
    45	    private final DbStatementType type;
    46	    // Column names to be returned from the inserted row or rows from the statement execution.
    47	    // Value of null (default) indicates no columns are set.
    48	    private List<String> columnNames = List.of();
    49	    // Whether PreparedStatement shall be created with Statement.RETURN_GENERATED_KEYS:
    50	    // - value of false (default) indicates that autoGeneratedKeys won't be passed to PreparedStatement creation
    51	    // - value of true indicates that Statement.RETURN_GENERATED_KEYS as autoGeneratedKeys will be passed
    52	    //   to PreparedStatement creation
    53	    private boolean returnGeneratedKeys;
    54	
    55	    /**
    56	     * Create a new instance.
    57	     *
    58	     * @param connectionPool connection pool
    59	     * @param context        execution context
    60	     */
    61	    JdbcStatementDml(JdbcConnectionPool connectionPool, DbStatementType type, JdbcExecuteContext context) {
    62	        super(connectionPool, context);
    63	        this.type = type;
    64	    }
    65	
    66	    @Override
    67	    public DbStatementType statementType() {
    68	        return type;
    69	    }
    70	
    71	    @Override
    72	    public long execute() {
    73	        return doExecute((future, context) -> {
    74	            try {
    75	                return doExecute(this, future, context);
    76	            } finally {
    77	                closeConnection();
    78	            }
    79	        });
    80	    }
    81	
    82	    @Override
    83	    public DbResultDml insert() {
    84	        return doExecute((future, context) -> doInsert(this, future, context, this::closeConnection));
    85	    }
    86	
    87	    @Override
    88	    public DbStatementDml returnGeneratedKeys() {
    89	        if (!columnNames.isEmpty()) {
    90	            throw new IllegalStateException("Method returnColumns(String[]) was already called to set specific column names.");
    91	        }
    92	        returnGeneratedKeys = true;
    93	        return this;
    94	    }
    95	
    96	    @Override
    97	    public DbStatementDml returnColumns(List<String> columnNames) {
    98	        if (returnGeneratedKeys) {
    99	            throw new IllegalStateException("Method returnGeneratedKeys() was already called.");
   100	        }
   101	        Objects.requireNonNull(columnNames, "List of column names value is null");
   102	        this.columnNames = Collections.unmodifiableList(columnNames);
   103	        return this;
   104	    }
   105	
   106	    @Override
   107	    protected PreparedStatement prepareStatement(Connection connection, String stmtName, String stmt) {
   108	        try {
   109	            connection(connection);
   110	            if (returnGeneratedKeys) {
   111	                return connection.prepareStatement(stmt, Statement.RETURN_GENERATED_KEYS);
   112	            } else if (!columnNames.isEmpty()) {
   113	                return connection.prepareStatement(stmt, columnNames.toArray(EMPTY_STRING_ARRAY));
   114	            }
   115	            return connection.prepareStatement(stmt);
   116	        } catch (SQLException e) {
   117	            throw new DbClientException(String.format("Failed to prepare statement: %s", stmtName), e);
   118	        }
   119	    }
   120	
   121	    /**
   122	     * Execute the given statement.
   123	     *
   124	     * @param dbStmt  db statement
   125	     * @param future  query future
   126	     * @param context service context
   127	     * @return query result
   128	     */
   129	    static long doExecute(JdbcStatement<? extends DbStatementDml> dbStmt,
   130	                          CompletableFuture<Long> future,
   131	                          DbClientServiceContext context) {
   132	
   133	        try (PreparedStatement statement = dbStmt.prepareStatement(context)) {
   134	            long result = statement.executeUpdate();
   135	            future.complete(result);
   136	            return result;
   137	        } catch (SQLException ex) {
   138	            dbStmt.closeConnection();
   139	            throw new DbStatementException("Failed to execute statement", dbStmt.context().statement(), ex);
   140	        }
   141	    }
   142	
   143	    /**
   144	     * Execute the given insert statement.
   145	     *
   146	     * @param dbStmt  db statement
   147	     * @param future  query future
   148	     * @param context service context
   149	     * @return query result
   150	     */
   151	    static DbResultDml doInsert(JdbcStatement<? extends DbStatementDml> dbStmt,
   152	                                CompletableFuture<Long> future,
   153	                                DbClientServiceContext context,
   154	                                Runnable onClose) {
   155	        PreparedStatement statement;
   156	        try {
   157	            statement = dbStmt.prepareStatement(context);
   158	            long result = statement.executeUpdate();
   159	            ResultSet rs = statement.getGeneratedKeys();
   160	            JdbcRow.Spliterator spliterator = new JdbcRow.Spliterator(rs, statement, dbStmt.context(), future);
   161	            Stream<DbRow> generatedKeys = autoClose(StreamSupport.stream(spliterator, false)
   162	                    .onClose(() -> {
   163	                        spliterator.close();
   164	                        if (onClose != null) {
   165	                            onClose.run();
   166	                        }
   167	                    }));
   168	            return DbResultDml.create(generatedKeys, result);
   169	        } catch (SQLException ex) {
   170	            dbStmt.closeConnection();
   171	            throw new DbStatementException("Failed to execute statement", dbStmt.context().statement(), ex);
   172	        }
   173	    }
   174	
   175	}
