    41	public class MongoDbStatementQuery extends MongoDbStatement<DbStatementQuery> implements DbStatementQuery {
    42	
    43	    private static final System.Logger LOGGER = System.getLogger(MongoDbStatementQuery.class.getName());
    44	
    45	    /**
    46	     * Create a new instance.
    47	     *
    48	     * @param db      MongoDb instance
    49	     * @param context context
    50	     */
    51	    MongoDbStatementQuery(MongoDatabase db, DbExecuteContext context) {
    52	        super(db, context);
    53	    }
    54	
    55	    @Override
    56	    public DbStatementType statementType() {
    57	        return DbStatementType.QUERY;
    58	    }
    59	
    60	    @Override
    61	    public Stream<DbRow> execute() {
    62	        return doExecute((future, context) -> {
    63	            String preparedStmt = prepareStatement(context);
    64	            try {
    65	                MongoStatement stmt = queryOrCommand(preparedStmt);
    66	                return switch (stmt.getOperation()) {
    67	                    case QUERY -> executeQuery(stmt, future);
    68	                    case COMMAND -> executeCommand(stmt, future);
    69	                    default -> throw new UnsupportedOperationException(String.format(
    70	                            "Operation %s is not supported by query", stmt.getOperation().toString()));
    71	                };
    72	            } catch (Exception e) {
    73	                throw new DbClientException(e.getMessage(), e);
    74	            }
    75	        });
    76	    }
    77	
    78	    private MongoStatement queryOrCommand(String statement) {
    79	        try {
    80	            return new MongoStatement(DbStatementType.QUERY, statement);
    81	        } catch (IllegalStateException e) {
    82	            // maybe this is a command?
    83	            try {
    84	                return new MongoStatement(DbStatementType.COMMAND, statement);
    85	            } catch (IllegalStateException _) {
    86	                // we want to report the original exception
    87	                throw e;
    88	            }
    89	        }
    90	    }
