    92	    private Stream<DbRow> executeCommand(MongoStatement stmt, CompletableFuture<Long> future) {
    93	        Document command = stmt.getQuery();
    94	        LOGGER.log(Level.DEBUG, () -> String.format("Command: %s", command.toString()));
    95	        Document doc = db().runCommand(command);
    96	        future.complete(1L);
    97	        return Stream.of(new MongoDbRow(doc, context()));
    98	    }
