   100	    private Stream<DbRow> executeQuery(MongoStatement stmt, CompletableFuture<Long> future) {
   101	        MongoCollection<Document> mc = db().getCollection(stmt.getCollection());
   102	        Document query = stmt.getQuery();
   103	        Document projection = stmt.getProjection();
   104	
   105	        LOGGER.log(Level.DEBUG, () -> String.format(
   106	                "Query: %s, Projection: %s",
   107	                query.toString(),
   108	                (projection != null ? projection : "N/A")));
   109	
   110	        FindIterable<Document> finder = mc.find(query);
   111	        if (projection != null) {
   112	            finder = finder.projection(projection);
   113	        }
   114	
   115	        MongoCursor<Document> it = finder.iterator();
   116	        future.complete(it.hasNext() ? 1L : 0L);
   117	        Spliterator<Document> spliterator = spliteratorUnknownSize(it, Spliterator.ORDERED);
   118	        Stream<Document> stream = StreamSupport.stream(spliterator, false);
   119	        return stream.map(doc -> new MongoDbRow(doc, context()));
   120	    }
