    87	    private <T> DbMapper<T> findMapper(Class<T> type, boolean fromTypes) {
    88	        DbMapper<?> mapper = byClass.computeIfAbsent(
    89	                type,
    90	                aClass -> fromProviders(type).orElseGet(() -> {
    91	                    GenericType<T> targetType = GenericType.create(type);
    92	                    if (fromTypes) {
    93	                        return notFoundMapper(targetType);
    94	                    }
    95	                    return findMapper(targetType, true);
    96	                }));
    97	        return (DbMapper<T>) mapper;
